import{_ as e,o as a,c as l,a2 as r}from"./chunks/framework.BQ1gajhD.js";const f=JSON.parse('{"title":"雍和宫","description":"","frontmatter":{},"headers":[],"relativePath":"religion/yonghegong.md","filePath":"religion/yonghegong.md","lastUpdated":null}'),n={name:"religion/yonghegong.md"};function o(i,t,d,h,s,g){return a(),l("div",null,[...t[0]||(t[0]=[r('<h1 id="雍和宫" tabindex="-1">雍和宫 <a class="header-anchor" href="#雍和宫" aria-label="Permalink to &quot;雍和宫&quot;">​</a></h1><blockquote><p>&quot;北京最大的藏传佛教寺院，香火最旺的皇家寺院。&quot;</p></blockquote><h2 id="简介" tabindex="-1">简介 <a class="header-anchor" href="#简介" aria-label="Permalink to &quot;简介&quot;">​</a></h2><p>雍和宫位于北京市东城区雍和宫大街，是北京最大的藏传佛教寺院，也是清朝中后期全国规格最高的佛教寺院。雍和宫原为清雍正帝即位前的府邸，乾隆九年（1744年）改为藏传佛教寺院。</p><h2 id="基本信息" tabindex="-1">基本信息 <a class="header-anchor" href="#基本信息" aria-label="Permalink to &quot;基本信息&quot;">​</a></h2><table tabindex="0"><thead><tr><th style="text-align:left;">项目</th><th style="text-align:left;">内容</th></tr></thead><tbody><tr><td style="text-align:left;"><strong>开放时间</strong></td><td style="text-align:left;">9:00-16:30（冬季至16:00）</td></tr><tr><td style="text-align:left;"><strong>门票价格</strong></td><td style="text-align:left;">25元</td></tr><tr><td style="text-align:left;"><strong>建议游玩</strong></td><td style="text-align:left;">2-3小时</td></tr><tr><td style="text-align:left;"><strong>最佳季节</strong></td><td style="text-align:left;">四季皆宜，春节香火最旺</td></tr><tr><td style="text-align:left;"><strong>交通方式</strong></td><td style="text-align:left;">地铁2号线/5号线雍和宫站</td></tr><tr><td style="text-align:left;"><strong>地址</strong></td><td style="text-align:left;">北京市东城区雍和宫大街12号</td></tr></tbody></table><h2 id="历史沿革" tabindex="-1">历史沿革 <a class="header-anchor" href="#历史沿革" aria-label="Permalink to &quot;历史沿革&quot;">​</a></h2><h3 id="王府时期" tabindex="-1">王府时期 <a class="header-anchor" href="#王府时期" aria-label="Permalink to &quot;王府时期&quot;">​</a></h3><p>清康熙三十三年（1694年），康熙帝在此建造府邸，赐予皇四子胤禛（即后来的雍正帝）。胤禛即位前在这里居住了近20年。</p><h3 id="雍亲王府" tabindex="-1">雍亲王府 <a class="header-anchor" href="#雍亲王府" aria-label="Permalink to &quot;雍亲王府&quot;">​</a></h3><p>胤禛被封为雍亲王，府邸称&quot;雍亲王府&quot;。1722年康熙帝驾崩，胤禛即位，年号雍正。</p><h3 id="行宫时期" tabindex="-1">行宫时期 <a class="header-anchor" href="#行宫时期" aria-label="Permalink to &quot;行宫时期&quot;">​</a></h3><p>雍正帝即位后，雍亲王府改为行宫，称&quot;雍和宫&quot;。雍正帝经常来此礼佛、休息。</p><h3 id="改为寺院" tabindex="-1">改为寺院 <a class="header-anchor" href="#改为寺院" aria-label="Permalink to &quot;改为寺院&quot;">​</a></h3><p>乾隆九年（1744年），乾隆帝为纪念其父雍正帝，将雍和宫改为藏传佛教寺院，成为清政府管理全国藏传佛教事务的中心。</p><h2 id="建筑布局" tabindex="-1">建筑布局 <a class="header-anchor" href="#建筑布局" aria-label="Permalink to &quot;建筑布局&quot;">​</a></h2><p>雍和宫共有五进院落，主要建筑沿中轴线分布。</p><h3 id="昭泰门" tabindex="-1">昭泰门 <a class="header-anchor" href="#昭泰门" aria-label="Permalink to &quot;昭泰门&quot;">​</a></h3><p>昭泰门是雍和宫的山门，门前有牌楼三座，东西两侧有钟楼、鼓楼。</p><h3 id="天王殿" tabindex="-1">天王殿 <a class="header-anchor" href="#天王殿" aria-label="Permalink to &quot;天王殿&quot;">​</a></h3><p>天王殿是雍和宫的第一重大殿，供奉弥勒佛和四大天王。</p><h3 id="雍和宫殿" tabindex="-1">雍和宫殿 <a class="header-anchor" href="#雍和宫殿" aria-label="Permalink to &quot;雍和宫殿&quot;">​</a></h3><p>雍和宫殿是雍和宫的主殿，原为雍亲王府的正殿。殿内供奉三世佛：释迦牟尼、燃灯佛、弥勒佛。</p><h3 id="永佑殿" tabindex="-1">永佑殿 <a class="header-anchor" href="#永佑殿" aria-label="Permalink to &quot;永佑殿&quot;">​</a></h3><p>永佑殿是雍和宫的第三重大殿，供奉无量寿佛。这里曾是雍正帝的书房和寝宫。</p><h3 id="法轮殿" tabindex="-1">法轮殿 <a class="header-anchor" href="#法轮殿" aria-label="Permalink to &quot;法轮殿&quot;">​</a></h3><p>法轮殿是雍和宫的重要殿堂，是举行法会的场所。殿内供奉宗喀巴大师像。</p><h4 id="五百罗汉山" tabindex="-1">五百罗汉山 <a class="header-anchor" href="#五百罗汉山" aria-label="Permalink to &quot;五百罗汉山&quot;">​</a></h4><p>法轮殿内有著名的&quot;五百罗汉山&quot;，用紫檀木雕刻而成，工艺精湛。</p><h3 id="万福阁" tabindex="-1">万福阁 <a class="header-anchor" href="#万福阁" aria-label="Permalink to &quot;万福阁&quot;">​</a></h3><p>万福阁是雍和宫最宏伟的建筑，是供奉弥勒大佛的地方。</p><h4 id="弥勒大佛" tabindex="-1">弥勒大佛 <a class="header-anchor" href="#弥勒大佛" aria-label="Permalink to &quot;弥勒大佛&quot;">​</a></h4><p>万福阁内的弥勒大佛是雍和宫的镇寺之宝：</p><table tabindex="0"><thead><tr><th style="text-align:left;">项目</th><th style="text-align:left;">数据</th></tr></thead><tbody><tr><td style="text-align:left;"><strong>高度</strong></td><td style="text-align:left;">18米（地上）+ 8米（地下）</td></tr><tr><td style="text-align:left;"><strong>材质</strong></td><td style="text-align:left;">整根白檀香木</td></tr><tr><td style="text-align:left;"><strong>重量</strong></td><td style="text-align:left;">约100吨</td></tr><tr><td style="text-align:left;"><strong>地位</strong></td><td style="text-align:left;">独木大佛，世界之最</td></tr></tbody></table><p>这尊大佛由一整根白檀香木雕刻而成，是雍和宫最珍贵的文物。</p><h2 id="藏传佛教" tabindex="-1">藏传佛教 <a class="header-anchor" href="#藏传佛教" aria-label="Permalink to &quot;藏传佛教&quot;">​</a></h2><h3 id="格鲁派" tabindex="-1">格鲁派 <a class="header-anchor" href="#格鲁派" aria-label="Permalink to &quot;格鲁派&quot;">​</a></h3><p>雍和宫属于藏传佛教格鲁派（黄教），是宗喀巴大师创立的教派。</p><h3 id="活佛转世" tabindex="-1">活佛转世 <a class="header-anchor" href="#活佛转世" aria-label="Permalink to &quot;活佛转世&quot;">​</a></h3><p>雍和宫设有&quot;金本巴瓶&quot;，用于掣签认定蒙藏地区活佛的转世灵童。</p><h3 id="法会" tabindex="-1">法会 <a class="header-anchor" href="#法会" aria-label="Permalink to &quot;法会&quot;">​</a></h3><p>雍和宫每年举行多次法会，其中农历正月初一的祈福法会和正月二十九的金刚舞法会最为隆重。</p><h2 id="游览攻略" tabindex="-1">游览攻略 <a class="header-anchor" href="#游览攻略" aria-label="Permalink to &quot;游览攻略&quot;">​</a></h2><h3 id="推荐路线" tabindex="-1">推荐路线 <a class="header-anchor" href="#推荐路线" aria-label="Permalink to &quot;推荐路线&quot;">​</a></h3><p><strong>经典路线（约2-3小时）</strong>：</p><p>昭泰门 → 天王殿 → 雍和宫殿 → 永佑殿 → 法轮殿 → 万福阁 → 绥成殿 → 出宫</p><p><strong>重点参观</strong>：</p><ol><li>万福阁的弥勒大佛（必看）</li><li>法轮殿的五百罗汉山</li><li>永佑殿的无量寿佛</li></ol><h3 id="交通方式" tabindex="-1">交通方式 <a class="header-anchor" href="#交通方式" aria-label="Permalink to &quot;交通方式&quot;">​</a></h3><table tabindex="0"><thead><tr><th style="text-align:left;">方式</th><th style="text-align:left;">站点</th></tr></thead><tbody><tr><td style="text-align:left;">地铁</td><td style="text-align:left;">2号线/5号线雍和宫站F口</td></tr><tr><td style="text-align:left;">公交</td><td style="text-align:left;">13路、116路、684路等雍和宫站</td></tr><tr><td style="text-align:left;">步行</td><td style="text-align:left;">从簋街步行约10分钟</td></tr></tbody></table><h3 id="实用贴士" tabindex="-1">实用贴士 <a class="header-anchor" href="#实用贴士" aria-label="Permalink to &quot;实用贴士&quot;">​</a></h3><ol><li><strong>香火旺盛</strong>：北京香火最旺的寺院，尤其是春节</li><li><strong>请香</strong>：门口可免费领取香</li><li><strong>参观礼仪</strong>：进入殿内脱帽，保持安静</li><li><strong>拍照</strong>：殿内禁止拍照</li><li><strong>周边美食</strong>：附近有著名的簋街（麻辣小龙虾）</li><li><strong>春节期间</strong>：人极多，建议错峰</li></ol><h2 id="周边景点" tabindex="-1">周边景点 <a class="header-anchor" href="#周边景点" aria-label="Permalink to &quot;周边景点&quot;">​</a></h2><table tabindex="0"><thead><tr><th style="text-align:left;">景点</th><th style="text-align:center;">距离</th><th style="text-align:left;">特色</th></tr></thead><tbody><tr><td style="text-align:left;">国子监</td><td style="text-align:center;">步行5分钟</td><td style="text-align:left;">古代最高学府</td></tr><tr><td style="text-align:left;">孔庙</td><td style="text-align:center;">步行5分钟</td><td style="text-align:left;">祭祀孔子的庙宇</td></tr><tr><td style="text-align:left;">簋街</td><td style="text-align:center;">步行10分钟</td><td style="text-align:left;">美食街，麻辣小龙虾</td></tr><tr><td style="text-align:left;">南锣鼓巷</td><td style="text-align:center;">步行20分钟</td><td style="text-align:left;">老北京胡同</td></tr><tr><td style="text-align:left;">地坛公园</td><td style="text-align:center;">步行15分钟</td><td style="text-align:left;">皇家祭坛</td></tr></tbody></table><h2 id="文化价值" tabindex="-1">文化价值 <a class="header-anchor" href="#文化价值" aria-label="Permalink to &quot;文化价值&quot;">​</a></h2><p>雍和宫是全国重点文物保护单位，是汉族地区佛教全国重点寺院。</p><p>雍和宫是北京最大的藏传佛教寺院，也是清政府管理全国藏传佛教事务的中心，在历史上发挥了重要作用。</p><p>雍和宫的弥勒大佛是木雕艺术的杰作，是中国佛教艺术的瑰宝。</p><hr><p><strong>📍 地址</strong>：北京市东城区雍和宫大街12号 <strong>📞 电话</strong>：010-64044499 <strong>🌐 官网</strong>：<a href="http://www.yonghegong.cn" target="_blank" rel="noreferrer">www.yonghegong.cn</a></p>',60)])])}const b=e(n,[["render",o]]);export{f as __pageData,b as default};
